SELECT AVG(y_pred - y_true) AS average_price_difference
FROM predictions
WHERE stock_id = 1 AND model_id = 'model_01';

SELECT open, close
FROM stock_prices
WHERE date = '2023-07-16' AND stock_id = 0;

SELECT high, low
FROM stock_prices
WHERE stock_id = 1 AND date = '2023-07-16';

SELECT SUM(volume) 
FROM stock_prices
WHERE stock_id = 1 AND date = '2023-07-17';

SELECT MAX(date)
  FROM predictions
  WHERE stock_id = 0;

SELECT MAX(close) AS highest_close
FROM stock_prices
WHERE date = '2023-10-01';
